import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { CountryService, Country } from '../services/country.service';

@Component({
  selector: 'app-country-detail',
  templateUrl: './country-detail.component.html',
  styleUrls: ['./country-detail.component.scss']
})
export class CountryDetailComponent implements OnInit {
  country: Country | null = null;
  borderCountries: Country[] = [];
  loading = true;
  error: string | null = null;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private countryService: CountryService
  ) {}

  ngOnInit(): void {
    const countryName = this.route.snapshot.paramMap.get('name');
    if (countryName) {
      this.loadCountryDetails(countryName);
    } else {
      this.error = 'Country not found';
      this.loading = false;
    }
  }

  loadCountryDetails(name: string): void {
    this.loading = true;
    this.countryService.getCountryByName(name).subscribe({
      next: (data) => {
        if (data.length > 0) {
          this.country = data[0];
          this.loadBorderCountries();
        } else {
          this.error = 'Country not found';
          this.loading = false;
        }
      },
      error: (err) => {
        this.error = 'Failed to load country details. Please try again later.';
        this.loading = false;
        console.error('Error loading country details:', err);
      }
    });
  }

  loadBorderCountries(): void {
    if (!this.country?.borders || this.country.borders.length === 0) {
      this.loading = false;
      return;
    }

    this.countryService.getCountryByCode(this.country.borders.join(',')).subscribe({
      next: (data) => {
        this.borderCountries = data;
        this.loading = false;
      },
      error: (error) => {
        console.error('Error loading border countries:', error);
        this.borderCountries = [];
        this.loading = false;
      }
    });
  }

  onBorderCountryClick(country: Country): void {
    this.router.navigate(['/country', country.name.common]);
  }

  onBackClick(): void {
    this.router.navigate(['/']);
  }

  getNativeName(): string {
    if (this.country?.name?.nativeName) {
      const nativeNames = Object.values(this.country.name.nativeName);
      if (nativeNames.length > 0 && nativeNames[0].common) {
        return nativeNames[0].common;
      }
    }
    return this.country?.name?.official || this.country?.name?.common || '';
  }

  getCurrencies(): string {
    if (!this.country?.currencies) return '';
    const currencies = Object.values(this.country.currencies);
    return currencies.map(currency => currency.name).join(', ');
  }

  getLanguages(): string {
    if (!this.country?.languages) return '';
    const languages = Object.values(this.country.languages);
    return languages.join(', ');
  }
}
<div class="country-detail-container" *ngIf="!loading && !error && country">
  <div class="container">
    <button class="back-button" (click)="onBackClick()">
      <span class="back-icon">←</span>
      Back
    </button>

    <div class="country-content">
      <div class="country-flag">
        <img [src]="country.flags.png" [alt]="'Flag of ' + country.name.common">
      </div>

      <div class="country-info">
        <h1 class="country-name">{{ country.name.common }}</h1>

        <div class="country-details-grid">
          <div class="details-column">
            <p class="detail-item">
              <span class="detail-label">Native Name:</span>
              <span class="detail-value">{{ getNativeName() }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Population:</span>
              <span class="detail-value">{{ country.population | number }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Region:</span>
              <span class="detail-value">{{ country.region }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Sub Region:</span>
              <span class="detail-value">{{ country.subregion || 'N/A' }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Capital:</span>
              <span class="detail-value">{{ country.capital && country.capital[0] ? country.capital[0] : 'N/A' }}</span>
            </p>
          </div>

          <div class="details-column">
            <p class="detail-item">
              <span class="detail-label">Top Level Domain:</span>
              <span class="detail-value">{{ country.tld && country.tld.length > 0 ? country.tld.join(', ') : 'N/A' }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Currencies:</span>
              <span class="detail-value">{{ getCurrencies() || 'N/A' }}</span>
            </p>
            <p class="detail-item">
              <span class="detail-label">Languages:</span>
              <span class="detail-value">{{ getLanguages() || 'N/A' }}</span>
            </p>
          </div>
        </div>

        <div class="border-countries" *ngIf="country.borders && country.borders.length > 0">
          <h3 class="border-title">Border Countries:</h3>
          <div class="border-buttons">
            <button 
              *ngFor="let borderCountry of borderCountries" 
              class="border-country-btn"
              (click)="onBorderCountryClick(borderCountry)">
              {{ borderCountry.name.common }}
            </button>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>

<div class="loading" *ngIf="loading">
  <p>Loading country details...</p>
</div>

<div class="error" *ngIf="error">
  <p>{{ error }}</p>
  <button class="retry-btn" (click)="onBackClick()">Back to Home</button>
</div>
